        const lastYearTotalRevenue = this.calculateTotalValues('revenue', true);
        return (h("div", { key: 'f301dd0d993ab52de155c26ada1daa3a5c865f56', class: "sales-by-country-summary__container" }, h("ir-stats-card", { key: 'c38a3b45d5d178b57cf8c6e604d7df44a3566e51', cardTitle: "Total Room Nights", icon: this.getIcon(totalRoomNights, lastYearTotalRoomNights), value: totalRoomNights.toString(), subtitle: lastYearTotalRoomNights ? `Last year ${lastYearTotalRoomNights}` : undefined }), h("ir-stats-card", { key: '61d396db8a07d32abc26bf865bd9fd49b28dbed4', icon: this.getIcon(totalGuests, lastYearTotalGuests), cardTitle: "Total Guests", value: totalGuests.toString(), subtitle: lastYearTotalGuests ? `Last year ${lastYearTotalGuests}` : undefined }), h("ir-stats-card", { key: '0590714d61cbfd78b3244bca69ecce7b39d2bbc7', icon: this.getIcon(totalRevenue, lastYearTotalRevenue), cardTitle: "Total Revenue", value: formatAmount(calendar_data.currency.symbol, totalRevenue), subtitle: lastYearTotalRevenue ? `Last year ${formatAmount(calendar_data.currency.symbol, lastYearTotalRevenue)}` : undefined })));
